<?php $days=[1=>'Monday',2=>'Tuesday',3=>'Wednesday',4=>'Thursday',5=>'Friday',6=>'Saturday',7=>'Sunday'];$current=null;foreach($schedules as$s)if((int)$s['id']===$edit)$current=$s;?><section class="admin-shell"><?php require __DIR__.'/_nav.php';?><div class="admin-main"><div class="admin-head"><div><span class="eyebrow">CLINICAL OPERATIONS</span><h1>Doctor Schedules</h1></div></div><form class="admin-panel admin-form" method="post" action="<?=url('admin/schedules')?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=e($current['id']??'')?>"><div class="form-grid"><label>Doctor<select name="doctor_id" required><option value="">Select doctor</option><?php foreach($doctors as$d):?><option value="<?=$d['id']?>" <?=($current['doctor_id']??'')==$d['id']?'selected':''?>><?=e($d['name'])?></option><?php endforeach;?></select></label><label>Day<select name="day_of_week" required><?php foreach($days as$k=>$v):?><option value="<?=$k?>" <?=($current['day_of_week']??'')==$k?'selected':''?>><?=$v?></option><?php endforeach;?></select></label><label>Start time<input type="time" name="start_time" value="<?=e($current['start_time']??'16:00')?>" required></label><label>End time<input type="time" name="end_time" value="<?=e($current['end_time']??'19:00')?>" required></label><label>Slot duration<select name="slot_duration_minutes"><option value="15">15 minutes</option><option value="20" <?=($current['slot_duration_minutes']??20)==20?'selected':''?>>20 minutes</option><option value="30" <?=($current['slot_duration_minutes']??'')==30?'selected':''?>>30 minutes</option></select></label><label>Room number<input name="room_number" value="<?=e($current['room_number']??'')?>"></label><label><span class="toggle"><input type="checkbox" name="is_active" value="1" <?=!isset($current['is_active'])||$current['is_active']?'checked':''?>> Active schedule</span></label></div><button class="btn"><?=$current?'Update':'Create'?> Schedule and Rebuild Slots</button></form><div class="admin-panel"><div class="table-wrap"><table><thead><tr><th>Doctor</th><th>Day</th><th>Time</th><th>Slot</th><th>Room</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($schedules as$s):?><tr><td><?=e($s['doctor_name'])?></td><td><?=$days[$s['day_of_week']]?></td><td><?=date('h:i A',strtotime($s['start_time']))?>–<?=date('h:i A',strtotime($s['end_time']))?></td><td><?=$s['slot_duration_minutes']?> min</td><td><?=e($s['room_number'])?></td><td><?=$s['is_active']?'Active':'Inactive'?></td><td><a href="<?=url('admin/schedules?id='.$s['id'])?>">Edit</a></td></tr><?php endforeach;?></tbody></table></div></div></div></section>

